import { useCallback, useRef } from 'react'

import useMap from './useMap'
import useSharedPopper from './useSharedPopper'

const INFO_DELAY_MS = 50
const WAIT_FOR_ELEMENT_TIMEOUT_MS = 5000

function waitForElement({ callback, id, mapContainer }) {
  let finalCallbackTimeoutId
  let observer
  let resolved = false
  let timeoutId

  let resolvePromise
  const promise = new Promise((resolve) => {
    resolvePromise = resolve
  })

  function resolveWait() {
    if (!resolved) {
      resolved = true
      resolvePromise()
    }
  }

  function cleanup() {
    clearTimeout(finalCallbackTimeoutId)
    clearTimeout(timeoutId)

    observer?.disconnect()
    resolveWait()
  }

  function scheduleCallback(element) {
    // A short delay is needed to ensure the marker is rendered in place.
    clearTimeout(finalCallbackTimeoutId)

    finalCallbackTimeoutId = setTimeout(() => {
      callback(element)
      resolveWait()
    }, INFO_DELAY_MS)
  }

  const doc = mapContainer?.current?.ownerDocument ?? document

  const existingElement = doc.getElementById(id)
  if (existingElement) {
    scheduleCallback(existingElement)

    return { cleanup, promise }
  }

  if (!mapContainer?.current || typeof MutationObserver === 'undefined') {
    resolveWait()

    return { cleanup, promise }
  }

  // Test to see if we have a valid Node
  const NodeConstructor =
    mapContainer.current?.ownerDocument?.defaultView?.Node ?? (typeof Node !== 'undefined' ? Node : undefined)

  if (!NodeConstructor || !(mapContainer.current instanceof NodeConstructor)) {
    resolveWait()

    return { cleanup, promise }
  }

  observer = new MutationObserver((mutations) => {
    mutations.some((mutation) => {
      return Array.from(mutation.addedNodes).some((node) => {
        if (node.nodeType === (NodeConstructor?.ELEMENT_NODE ?? 1)) {
          if (node.id === id) {
            observer.disconnect()

            scheduleCallback(node)

            return true
          }

          const element = node.querySelector && node.querySelector(`#${id}`)
          if (element) {
            observer.disconnect()

            scheduleCallback(element)

            return true
          }
        }
        return false
      })
    })
  })

  timeoutId = setTimeout(() => {
    cleanup()
  }, WAIT_FOR_ELEMENT_TIMEOUT_MS)

  try {
    observer.observe(mapContainer.current, { childList: true, subtree: true })
  } catch {
    cleanup()

    return { cleanup, promise }
  }

  return { cleanup, promise }
}

export function isInteractable({ info, label, onBlur, onClick, onDragEnd, onFocus, onMouseEnter, onMouseLeave } = {}) {
  return Boolean(info || label || onBlur || onClick || onDragEnd || onFocus || onMouseEnter || onMouseLeave)
}

function isSameMarker({ getClusterId, marker, markerId, openMarkerElementRef, openMarkerIdRef }) {
  const currentMarkerId = getClusterId?.() || markerId
  const isSameMarkerId = currentMarkerId && openMarkerIdRef.current === currentMarkerId

  if (isSameMarkerId) {
    return true
  }

  // If no markerId, check by element reference
  const currentMarkerElement = marker?.element || marker
  const isSameMarkerElement = currentMarkerElement && openMarkerElementRef.current === currentMarkerElement

  return isSameMarkerElement
}

export function useOpenInfo() {
  const isInfoOpenRef = useRef(false)
  const openInfoRef = useRef(null)
  const openMarkerIdRef = useRef(null)
  const openMarkerElementRef = useRef(null)
  const { mapContainer, whenIdle, zoomPan } = useMap()
  const sharedPopper = useSharedPopper()

  const openInfo = useCallback(
    async ({ getClusterCentroid, getClusterId, marker, markerId, markerProps, proximityCentroid, skipPan }) => {
      const { info, latitude, longitude, onInfoClosed } = markerProps || {}
      let markerReadyPromise = Promise.resolve()

      if (!info) {
        return
      }

      // If the same marker's info is already open with the same content, don't close and reopen it
      const isSameMarkerOpen = isSameMarker({ getClusterId, marker, markerId, openMarkerElementRef, openMarkerIdRef })
      const isSameInfo = openInfoRef.current === info

      if (isSameMarkerOpen && isSameInfo) {
        return
      }

      sharedPopper.close()

      if (!skipPan) {
        let clusterCentroid = getClusterCentroid?.()
        zoomPan({
          latitude: clusterCentroid?.latitude ?? proximityCentroid?.latitude ?? latitude,
          longitude: clusterCentroid?.longitude ?? proximityCentroid?.longitude ?? longitude,
        })

        if (getClusterCentroid) {
          // Correct zoomPan location if a cluster comes into existence after panning.
          await whenIdle({
            callback: () => {
              clusterCentroid = getClusterCentroid?.()

              if (clusterCentroid) {
                zoomPan({ latitude: clusterCentroid.latitude, longitude: clusterCentroid.longitude })
              }
            },
          })
        }
      }

      function whenIdleCallback({ markerElement, markerId: currentMarkerId }) {
        sharedPopper.callInfoChangedHandlers()

        const interactable = isInteractable(markerProps)

        if (interactable) {
          markerElement.classList.add('focus')
        }

        sharedPopper.open({ info, target: markerElement })

        markerElement.style.zIndex = 3

        isInfoOpenRef.current = true
        openInfoRef.current = info
        openMarkerIdRef.current = currentMarkerId
        openMarkerElementRef.current = markerElement

        sharedPopper.addOnInfoChangedHandler(() => {
          if (interactable) {
            markerElement.classList.remove('hover')
          }

          markerElement.classList.remove('focus')

          isInfoOpenRef.current = false
          openInfoRef.current = null
          openMarkerIdRef.current = null
          openMarkerElementRef.current = null

          markerElement.style.zIndex = null
        })

        if (onInfoClosed) {
          sharedPopper.addOnInfoClosedHandler({ handler: onInfoClosed, id: currentMarkerId ?? markerElement })
        }
      }

      await whenIdle({
        callback: () => {
          const finalMarkerId = getClusterId?.() || markerId

          if (finalMarkerId) {
            const { cleanup, promise } = waitForElement({
              callback: (element) => whenIdleCallback({ markerElement: element, markerId: finalMarkerId }),
              id: finalMarkerId,
              mapContainer,
            })

            markerReadyPromise = promise

            // Ensure the observer is disconnected when the info changes/closes.
            sharedPopper.addOnInfoChangedHandler(cleanup)
          } else if (marker) {
            whenIdleCallback({ markerElement: marker.element || marker, markerId })
            markerReadyPromise = Promise.resolve()
          }
        },
      })

      await markerReadyPromise
    },
    [mapContainer, sharedPopper, whenIdle, zoomPan]
  )

  return {
    isInfoOpenRef,
    openInfo,
  }
}
