import React, { useEffect, useState } from 'react'
import { css, cx } from '@linaria/core'
import { rawDayColors } from '@fs/zion-ui/quarks-authorized-use-only'
import PropTypes from 'prop-types'
import { Image } from '@fs/zion-ui'

import colors from './colors'
import useMap from '../hooks/useMap'
import { draggableDirectionsValidator, getCursor } from './draggableDirectionsConstraints'

const iconClassName = css`
  align-items: center;
  block-size: 100%;
  display: flex;
  inline-size: 100%;
  justify-content: center;

  > span {
    // This is needed for the icon to align correctly in the AzureMap Marker.
    vertical-align: initial;
  }

  svg {
    stroke: var(--stroke);
    stroke-width: 2;
    paint-order: stroke fill;
  }
`

const svgClassName = css`
  block-size: var(--blockSize);
  cursor: var(--cursor);
  inline-size: var(--inlineSize);
  overflow: visible;

  [aria-grabbed='true'] & {
    cursor: grabbing;
  }

  > circle {
    fill: var(--fill);
  }

  .hover &,
  .focus & {
    > circle {
      fill: var(--invertFill);
    }

    > foreignObject > img {
      filter: brightness(1.25);
    }

    > g {
      display: block;
    }
  }
`

const svgHoverClassName = css`
  &:hover {
    > circle {
      fill: var(--invertFill);
    }
  }
`

const imageClassName = css`
  > img {
    block-size: 100%;
    border-radius: 50%;
    inline-size: 100%;
    pointer-events: none;
    user-select: none;
  }
`

const imageFocusedClassName = css`
  > img {
    filter: brightness(1.25);
  }
`

const dragCrossClassName = css`
  display: none;
  translate: 50% calc(100% + 2px);
`

const textClassName = css`
  dominant-baseline: central;
  fill: ${rawDayColors.gray['00']};
  font-size: 18px;
  font-weight: 700;
  paint-order: stroke fill;
  text-anchor: middle;
  user-select: none;
`

const monogramClassName = css`
  font-family: var(--font-families-headings);
  font-size: 20px;
`

const draggingCursorClassName = css`
  &,
  & * {
    cursor: var(--dragging-cursor) !important;
  }
`

function processChars({ chars }) {
  if (chars === null || chars === undefined) return { processedChars: chars, length: 0 }

  const charsLength = `${chars}`.length
  let processedChars = chars

  const isNumber = typeof chars === 'number'
  if (isNumber && chars > 999) {
    processedChars = '999+'
  } else if (charsLength > 4) {
    processedChars = `${chars}`.slice(0, 4)
  }

  const isMonogram = charsLength === 1 && !isNumber

  return { isMonogram, processedChars, length: charsLength }
}

function getMarkerSize({ charsLength, imageSrc }) {
  if (imageSrc) return 45

  if (charsLength === 1 || charsLength === 2) return 50
  if (charsLength === 3) return 55
  if (charsLength > 3) return 60

  return 45
}

export default function RoundMarker({
  chars,
  cluster,
  color,
  draggable,
  draggableDirections,
  focused,
  interactable,
  Icon,
  imageSrc,
  testId,
}) {
  const { azure, bing, mapContainer } = useMap()
  const [isGrabbing, setIsGrabbing] = useState(false)
  const STROKE_WIDTH = 1.5

  let { fill, invertFill } = colors[color] || colors.red
  const stroke = colors[color]?.stroke || colors.red.stroke

  if (focused) {
    const fillTemp = fill
    fill = invertFill
    invertFill = fillTemp
  }

  const cursor = getCursor({ draggable, draggableDirections, interactable, isGrabbing })
  const { isMonogram, processedChars, length: charsLength } = processChars({ chars })
  const size = getMarkerSize({ charsLength, imageSrc })

  const radius = size / 2 - STROKE_WIDTH / 2
  const numConcentric = cluster ? 2 : 0

  const CONCENTRIC_OPACITY = 0.3
  const CONCENTRIC_SPREAD = 6
  const totalSize = size + CONCENTRIC_SPREAD * numConcentric * 2
  const center = totalSize / 2

  const iconX = center - size / 2
  const iconY = center - size / 2

  const imageSize = size - STROKE_WIDTH * 2
  const imageX = center - imageSize / 2
  const imageY = center - imageSize / 2

  function handleMouseDown() {
    if (draggable) setIsGrabbing(true)
  }

  // Manage global dragging cursor state on the map container
  // WHY: When dragging a marker, apply the dragging cursor to the entire map container
  // so the cursor remains consistent even when the mouse moves outside the marker bounds
  useEffect(() => {
    const currentMapContainer = mapContainer?.current

    if (!isGrabbing || !draggable || !currentMapContainer) {
      return undefined
    }

    currentMapContainer.classList.add(draggingCursorClassName)
    currentMapContainer.style.setProperty('--dragging-cursor', cursor)

    function handleGlobalMouseUp() {
      setIsGrabbing(false)
    }

    document.addEventListener('mouseup', handleGlobalMouseUp)

    return () => {
      if (currentMapContainer) {
        currentMapContainer.classList.remove(draggingCursorClassName)
        currentMapContainer.style.removeProperty('--dragging-cursor')
      }

      document.removeEventListener('mouseup', handleGlobalMouseUp)
    }
  }, [isGrabbing, draggable, cursor, mapContainer])

  return (
    <svg
      // The aria-label is on the parent marker element, this svg is considered decorative.
      aria-hidden="true"
      className={cx(svgClassName, !focused && interactable && svgHoverClassName)}
      data-testid={testId}
      onMouseDown={handleMouseDown}
      style={{
        '--blockSize': `${totalSize}px`,
        '--cursor': cursor,
        '--fill': fill,
        '--inlineSize': `${totalSize}px`,
        '--invertFill': invertFill,
      }}
      viewBox={`0 0 ${totalSize} ${totalSize}`}
      xmlns="http://www.w3.org/2000/svg"
    >
      {(azure || bing || draggableDirections) && draggable && (
        <g className={dragCrossClassName}>
          <line x1={-6.5} y1={-5} x2={6.5} y2={5} stroke="#888888" strokeWidth="1" strokeLinecap="round" />
          <line x1={6.5} y1={-5} x2={-6.5} y2={5} stroke="#888888" strokeWidth="1" strokeLinecap="round" />
        </g>
      )}
      {Array.from({ length: numConcentric }).map((_, index) => {
        const key = `concentric-${index}`

        return (
          <circle
            key={key}
            cx={center}
            cy={center}
            r={radius + CONCENTRIC_SPREAD * (index + 1)}
            opacity={(CONCENTRIC_OPACITY / numConcentric) * (numConcentric - index)}
          />
        )
      })}
      <circle cx={center} cy={center} r={radius} stroke={stroke} strokeWidth={STROKE_WIDTH} />
      {!Icon && processedChars !== undefined && processedChars !== null && (
        <text
          className={cx(textClassName, isMonogram && monogramClassName)}
          dx={isMonogram ? 0.45 : 0}
          dy={isMonogram ? 2 : 0}
          stroke={stroke}
          strokeWidth={2}
          x={center}
          y={center}
        >
          {processedChars}
        </text>
      )}
      {Icon && (
        <foreignObject height={size} width={size} x={iconX} y={iconY}>
          <div className={iconClassName} style={{ '--stroke': stroke }}>
            <Icon color={rawDayColors.gray['00']} size="sm" />
          </div>
        </foreignObject>
      )}
      {imageSrc && (
        <foreignObject
          className={cx(imageClassName, focused && imageFocusedClassName)}
          height={imageSize}
          width={imageSize}
          x={imageX}
          y={imageY}
        >
          <Image
            alt=""
            draggable={false}
            // Prevent showing a broken image icon if image fails to load
            failureFallback={<div />}
            loading="lazy"
            src={imageSrc}
          />
        </foreignObject>
      )}
    </svg>
  )
}

RoundMarker.propTypes = {
  chars: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
  cluster: PropTypes.bool,
  color: PropTypes.oneOf(['blue', 'gray', 'green', 'purple', 'red', 'yellow']),
  draggable: PropTypes.bool,
  draggableDirections: draggableDirectionsValidator,
  focused: PropTypes.bool,
  interactable: PropTypes.bool,
  Icon: PropTypes.func,
  imageSrc: PropTypes.string,
  testId: PropTypes.string,
}
