import React, { useEffect, useState } from 'react'
import { css, cx } from '@linaria/core'
import PropTypes from 'prop-types'

import colors from './colors'
import useMap from '../hooks/useMap'

const svgClassName = css`
  block-size: var(--blockSize);
  cursor: var(--cursor);
  inline-size: var(--inlineSize);
  overflow: visible;

  > circle {
    fill: var(--fill);
  }

  .hover &,
  .focus & {
    > circle {
      fill: var(--invertFill);
    }
  }
`

const svgHoverClassName = css`
  &:hover {
    > circle {
      fill: var(--invertFill);
    }
  }
`

const draggingCursorClassName = css`
  &,
  & * {
    cursor: var(--dragging-cursor) !important;
  }
`

const CURSORS = {
  n: 'n-resize',
  s: 's-resize',
  e: 'e-resize',
  w: 'w-resize',

  ne: 'ne-resize',
  nw: 'nw-resize',
  se: 'se-resize',
  sw: 'sw-resize',
  ns: 'ns-resize',
  ew: 'ew-resize',

  nesw: 'nesw-resize',
  nwse: 'nwse-resize',

  'e,s,w': 's-resize',
  'e,n,w': 'n-resize',
  'e,n,s': 'e-resize',
  'n,s,w': 'w-resize',

  grab: 'grab',
}

function getCursor({ draggableDirections }) {
  if (!draggableDirections || draggableDirections.length === 0) {
    return CURSORS.grab
  }

  // Single direction
  if (draggableDirections.length === 1) {
    const dir = draggableDirections[0]
    return CURSORS[dir] || CURSORS.grab
  }

  // Multiple directions - determine cursor based on combination
  const sorted = [...draggableDirections].sort().join(',')

  // Same axis pairs
  if (sorted === 'n,s') return CURSORS.ns
  if (sorted === 'e,w') return CURSORS.ew

  // Diagonal line pairs
  if (sorted === 'ne,sw') return CURSORS.nesw
  if (sorted === 'nw,se') return CURSORS.nwse

  // Two cardinals on different axes (quadrant resize)
  if (sorted === 'e,n') return CURSORS.ne
  if (sorted === 'n,w') return CURSORS.nw
  if (sorted === 'e,s') return CURSORS.se
  if (sorted === 's,w') return CURSORS.sw

  // Three cardinals - specific cursors
  if (CURSORS[sorted]) return CURSORS[sorted]

  // Default fallback
  return CURSORS.grab
}

const STROKE_WIDTH = 1.5
const SIZE = 24
const RADIUS = SIZE / 2 - STROKE_WIDTH / 2
const CENTER = SIZE / 2

export default function ResizeHandleMarker({ color, draggableDirections }) {
  const { fullscreenContainer, mapContainer } = useMap()
  const [isGrabbing, setIsGrabbing] = useState(false)

  const { fill, invertFill } = colors[color] || colors.red
  const stroke = colors[color]?.stroke || colors.red.stroke

  const cursor = getCursor({ draggableDirections })

  function handleMouseDown() {
    setIsGrabbing(true)

    // Add dragging class immediately on mousedown to disable pointer events on other markers
    // This must happen synchronously before any other events can fire
    const currentMapContainer = mapContainer?.current
    if (currentMapContainer) {
      currentMapContainer.classList.add(draggingCursorClassName)
      currentMapContainer.style.setProperty('--dragging-cursor', cursor)
      currentMapContainer.classList.add('dragging')
    }

    fullscreenContainer?.classList.add('dragging')
  }

  useEffect(() => {
    const currentMapContainer = mapContainer?.current
    if (!isGrabbing || !currentMapContainer) {
      return undefined
    }

    function handleGlobalMouseUp() {
      setIsGrabbing(false)
    }

    document.addEventListener('mouseup', handleGlobalMouseUp)

    return () => {
      currentMapContainer.classList.remove(draggingCursorClassName)
      currentMapContainer.style.removeProperty('--dragging-cursor')
      currentMapContainer.classList.remove('dragging')

      fullscreenContainer?.classList.remove('dragging')

      document.removeEventListener('mouseup', handleGlobalMouseUp)
    }
  }, [cursor, fullscreenContainer, isGrabbing, mapContainer])

  return (
    <svg
      // The aria-label is on the parent marker element, this svg is considered decorative.
      aria-hidden="true"
      className={cx(svgClassName, svgHoverClassName)}
      data-testid="resize-handle-svg"
      onMouseDown={handleMouseDown}
      style={{
        '--blockSize': `${SIZE}px`,
        '--cursor': cursor,
        '--fill': fill,
        '--inlineSize': `${SIZE}px`,
        '--invertFill': invertFill,
      }}
      viewBox={`0 0 ${SIZE} ${SIZE}`}
      xmlns="http://www.w3.org/2000/svg"
    >
      <circle cx={CENTER} cy={CENTER} r={RADIUS} stroke={stroke} strokeWidth={STROKE_WIDTH} />
    </svg>
  )
}

ResizeHandleMarker.propTypes = {
  color: PropTypes.oneOf(['blue', 'gray', 'green', 'purple', 'red', 'yellow']),
  draggableDirections: PropTypes.arrayOf(PropTypes.string),
}
