import React, { useEffect, useState } from 'react'
import { css } from '@linaria/core'
import { rawDayColors } from '@fs/zion-ui/quarks-authorized-use-only'
import PropTypes from 'prop-types'

import colors from './colors'
import config from './config.json'
import useMap from '../hooks/useMap'
import { draggableDirectionsValidator, getCursor } from './draggableDirectionsConstraints'

const svgClassName = css`
  block-size: var(--blockSize);
  cursor: var(--cursor);
  inline-size: var(--inlineSize);
  overflow: visible;
  pointer-events: auto;

  > path {
    fill: var(--fill);
  }

  .hover & {
    > path {
      fill: var(--invertFill);
    }

    > g {
      display: block;
    }
  }

  .focus & {
    > path,
    > circle:not([fill]) {
      fill: var(--invertFill);
    }

    > g {
      display: block;
    }
  }
`

const charsClassName = css`
  fill-opacity: 0.87;
  fill: ${rawDayColors.gray[100]};
  font-family: Monaco, Verdana, sans-serif;
  font-size: 11px;
  font-style: normal;
  font-weight: 100;
  letter-spacing: 0.0125em;
  user-select: none;
`

const iconClassName = css`
  > span {
    // This is needed for the icon to align correctly in the AzureMap Marker.
    vertical-align: initial;
  }
`

const dragCrossClassName = css`
  display: none;
  translate: 50% calc(100% + 2px);
`

const draggingCursorClassName = css`
  &,
  & * {
    cursor: var(--dragging-cursor) !important;
  }
`

function getConfig({ chars, Icon }) {
  let selectedConfig = config.default // Use a minimum of 24px to comply with A11Y

  const hasChars = chars !== undefined && chars !== null && `${chars}`.length > 0
  if (Icon || (hasChars && `${chars}`.length === 3)) {
    selectedConfig = config.iconOrThreeChars
  } else if (hasChars) {
    const charLength = `${chars}`.length

    if (charLength < 3) {
      selectedConfig = config.oneOrTwoChars
    } else if (charLength === 4) {
      selectedConfig = config.fourChars
    } else if (charLength > 4) {
      selectedConfig = config.fiveChars
    }
  }

  return selectedConfig
}

export default function TeardropMarker({
  chars,
  color,
  draggable,
  draggableDirections,
  focused,
  Icon,
  interactable,
  testId,
}) {
  const { azure, bing, mapContainer } = useMap()
  const [isGrabbing, setIsGrabbing] = useState(false)
  const selectedColor = colors[color] || colors.red
  const fill = focused ? selectedColor.invertFill : selectedColor.fill
  const invertFill = interactable ? selectedColor.invertFill : fill
  const stroke = selectedColor.stroke

  const selectedConfig = getConfig({ chars, Icon })
  const cursor = getCursor({ draggable, draggableDirections, interactable, isGrabbing })

  if (typeof chars === 'number' && chars > 9999) {
    chars = '9999+'
  } else if (chars?.length > 5) {
    chars = `${chars}`.slice(0, 5)
  }

  function handleMouseDown() {
    if (draggable) setIsGrabbing(true)
  }

  // Manage global dragging cursor state on the map container
  // WHY: When dragging a marker, apply the dragging cursor to the entire map container
  // so the cursor remains consistent even when the mouse moves outside the marker bounds
  useEffect(() => {
    const currentMapContainer = mapContainer?.current
    if (!isGrabbing || !draggable || !currentMapContainer) {
      return undefined
    }

    currentMapContainer.classList.add(draggingCursorClassName)
    currentMapContainer.style.setProperty('--dragging-cursor', cursor)

    function handleGlobalMouseUp() {
      setIsGrabbing(false)
    }

    document.addEventListener('mouseup', handleGlobalMouseUp)

    return () => {
      if (currentMapContainer) {
        currentMapContainer.classList.remove(draggingCursorClassName)
        currentMapContainer.style.removeProperty('--dragging-cursor')
      }

      document.removeEventListener('mouseup', handleGlobalMouseUp)
    }
  }, [isGrabbing, draggable, cursor, mapContainer])

  return (
    <svg
      // The aria-label is on the parent marker element, this svg is considered decorative.
      aria-hidden="true"
      className={svgClassName}
      data-testid={testId}
      onMouseDown={handleMouseDown}
      style={{
        '--blockSize': `${selectedConfig.blockSize}px`,
        '--cursor': cursor,
        '--fill': fill,
        '--inlineSize': `${selectedConfig.inlineSize}px`,
        '--invertFill': invertFill,
      }}
      viewBox={selectedConfig.viewBox}
      xmlns="http://www.w3.org/2000/svg"
    >
      {(azure || bing || draggableDirections) && draggable && (
        <g className={dragCrossClassName}>
          <line x1={-6.5} y1={-5} x2={6.5} y2={5} stroke="#888888" strokeWidth="1" strokeLinecap="round" />
          <line x1={6.5} y1={-5} x2={-6.5} y2={5} stroke="#888888" strokeWidth="1" strokeLinecap="round" />
        </g>
      )}
      <path d={selectedConfig.path} stroke={stroke} strokeWidth="1.5" />
      <circle cx={selectedConfig.cx} cy={selectedConfig.cy} fill={rawDayColors.gray['00']} r={selectedConfig.r} />
      {Icon && (
        <foreignObject
          className={iconClassName}
          height={selectedConfig.cy}
          width={selectedConfig.cx}
          x={selectedConfig.cx / 2}
          y={selectedConfig.cy / 2}
        >
          <Icon color={rawDayColors.gray[100]} size="xs" />
        </foreignObject>
      )}
      {!Icon && chars !== undefined && chars !== null && (
        <text
          className={charsClassName}
          dominantBaseline="central"
          textAnchor="middle"
          x={selectedConfig.cx}
          y={selectedConfig.cy}
        >
          {chars}
        </text>
      )}
    </svg>
  )
}

TeardropMarker.propTypes = {
  chars: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
  color: PropTypes.oneOf(['blue', 'gray', 'green', 'purple', 'red', 'yellow']),
  draggable: PropTypes.bool,
  draggableDirections: draggableDirectionsValidator,
  focused: PropTypes.bool,
  Icon: PropTypes.func,
  interactable: PropTypes.bool,
  testId: PropTypes.string,
}
