import { useMemo, useEffect, useCallback, useImperativeHandle, useRef, useState } from 'react'
import PropTypes from 'prop-types'
import { useEvent, useRandomId } from '@fs/zion-frontend-friends'

import { useChildrenBoundsApi } from '../../../../components/Map/hooks/useChildrenBounds'
import useMap from './useMap'
import useSharedPopper from './useSharedPopper'
import { isInteractable, useOpenInfo } from './useOpenInfo'

function createStyleHelpers({ draggable, draggableDirections, interactable, isInfoOpenRef, marker }) {
  return {
    addFocus() {
      if (interactable || (draggable && draggableDirections)) {
        marker.classList.add('focus')
      }
    },
    removeFocus() {
      if ((interactable || (draggable && draggableDirections)) && !isInfoOpenRef.current) {
        marker.classList.remove('focus')
      }
    },
    addHover() {
      if (interactable || (draggable && draggableDirections)) {
        marker.classList.add('hover')
      }
    },
    removeHover() {
      if (interactable || (draggable && draggableDirections)) {
        marker.classList.remove('hover')
      }
    },
  }
}

function createLabelHelpers({ label, sharedPopper }) {
  return {
    openLabel({ target }) {
      if (label && !sharedPopper.isInfoOpenRef.current) {
        sharedPopper.open({ label, target })
      }
    },
    closeLabel() {
      if (label && !sharedPopper.isInfoOpenRef.current) {
        sharedPopper.close()
      }
    },
  }
}

function createMapOptionsHelpers({
  azure,
  bing,
  draggable,
  gestureHandling,
  interactable,
  isInfoOpenRef,
  map,
  marker,
  nonInteractive,
}) {
  return {
    reset({ event }) {
      if (!azure && !bing) {
        map.setOptions({ gestureHandling })
      }

      if (azure && !nonInteractive) {
        map.setUserInteraction({
          interactive: true,
        })
      }

      if (!isInfoOpenRef.current && document.activeElement !== event.target) {
        marker.style.zIndex = null
      }
    },
    set() {
      if (!azure && !bing && interactable) {
        map.setOptions({ gestureHandling: 'none' })
      }

      if (azure && interactable) {
        map.setUserInteraction({
          interactive: false,
        })
      }

      if ((interactable || draggable) && !isInfoOpenRef.current) {
        marker.style.zIndex = 2
      }
    },
  }
}

export default function useMarker(props, forwardedRef) {
  const {
    cluster,
    draggable,
    draggableDirections,
    info,
    label,
    latitude,
    longitude,
    metadata,
    onBlur,
    onClick,
    onDrag,
    onDragEnd,
    onFocus,
    onInfoClosed,
    onMouseEnter,
    onMouseLeave,
    onChange,
  } = props

  const [marker, setMarker] = useState()
  const initialPropsRef = useRef(props)
  const positionRef = useRef({ latitude, longitude })
  const childrenBoundsApi = useChildrenBoundsApi()
  const { azure, bing, fullscreenContainer, gestureHandling, map, nonInteractive } = useMap()
  const sharedPopper = useSharedPopper()
  const markerId = useRandomId()
  const interactable = isInteractable(props)
  const { openInfo: withOpenInfo, isInfoOpenRef } = useOpenInfo()

  // Stable callback that never recreates - RFC pattern
  const stableOnChange = useEvent(onChange)

  const openInfo = useCallback(
    ({ skipPan } = {}) => {
      return withOpenInfo({
        marker,
        markerProps: { info, latitude, longitude, onInfoClosed },
        skipPan,
      })
    },
    [info, latitude, longitude, marker, onInfoClosed, withOpenInfo]
  )

  useImperativeHandle(forwardedRef, () => {
    return marker
      ? {
          openInfo: info ? openInfo : undefined,
        }
      : null
  }, [info, marker, openInfo])

  const eventListeners = useMemo(() => {
    if (!marker) {
      return {}
    }

    const markerElement = marker.element || marker

    isInfoOpenRef.current = false

    const styleHelpers = createStyleHelpers({
      draggable,
      draggableDirections,
      interactable,
      isInfoOpenRef,
      marker: markerElement,
    })
    const labelHelpers = createLabelHelpers({ label, sharedPopper })
    const mapHelpers = createMapOptionsHelpers({
      azure,
      bing,
      draggable,
      gestureHandling,
      interactable,
      isInfoOpenRef,
      map,
      marker: markerElement,
      nonInteractive,
    })

    function getArgs(event) {
      return {
        metadata,
        position: {
          latitude: event.latLng?.lat() ?? marker.options?.position[1] ?? positionRef.current.latitude,
          longitude: event.latLng?.lng() ?? marker.options?.position[0] ?? positionRef.current.longitude,
        },
      }
    }

    function hasDraggingClass() {
      return fullscreenContainer?.classList.contains('dragging')
    }

    let dragging = false
    return {
      blur: (event) => {
        if (dragging || hasDraggingClass()) return

        styleHelpers.removeFocus()
        labelHelpers.closeLabel()
        mapHelpers.reset({ event })
        onBlur?.(getArgs(event))
      },
      click: (event) => {
        onClick?.(getArgs(event))

        if (!cluster) {
          sharedPopper.callInfoChangedHandlers()
          openInfo({ skipPan: true })
        }
      },
      dragstart: () => {
        // Note: The `dragging` variable or class are used so that the GoogleMap Markers handle pointer-events and z-index correctly when dragging.
        dragging = true
        fullscreenContainer?.classList.add('dragging')
      },
      drag: (event) => {
        sharedPopper.update({ event: event.domEvent ?? event })
        onDrag?.(getArgs(event))
      },
      dragend: (event) => {
        dragging = false
        fullscreenContainer?.classList.remove('dragging')
        positionRef.current = {
          latitude: event.latLng?.lat() ?? positionRef.current.latitude,
          longitude: event.latLng?.lng() ?? positionRef.current.longitude,
        }
        onDragEnd?.(getArgs(event))
      },
      focus: (event) => {
        if (dragging || hasDraggingClass()) return

        styleHelpers.addFocus()
        labelHelpers.openLabel({ target: event.target })
        mapHelpers.set()
        onFocus?.(getArgs(event))
      },
      mouseenter: (event) => {
        if (dragging || hasDraggingClass()) return

        // Prevent these events from bubbling to any boundaries
        event.stopPropagation()

        styleHelpers.addHover()
        labelHelpers.openLabel({ target: event.target })
        mapHelpers.set()
        onMouseEnter?.(getArgs(event))
      },
      mouseleave: (event) => {
        if (dragging || hasDraggingClass()) return

        // Prevent these events from bubbling to any boundaries
        event.stopPropagation()

        styleHelpers.removeHover()

        if (document.activeElement !== event.target && !sharedPopper.isInfoOpenRef.current) {
          sharedPopper.close()
        } else if (!isInfoOpenRef.current) {
          markerElement.style.zIndex = 1
        }

        mapHelpers.reset({ event })
        onMouseLeave?.(getArgs(event))
      },
      mousemove: (event) => {
        if (dragging || hasDraggingClass()) return

        // Prevent these events from bubbling to any boundaries
        event.stopPropagation()
      },
    }
  }, [
    azure,
    bing,
    cluster,
    draggable,
    draggableDirections,
    fullscreenContainer,
    gestureHandling,
    interactable,
    isInfoOpenRef,
    label,
    map,
    marker,
    metadata,
    nonInteractive,
    onBlur,
    onClick,
    onDrag,
    onDragEnd,
    onFocus,
    onMouseEnter,
    onMouseLeave,
    openInfo,
    sharedPopper,
  ])

  // Add or remove the marker from the children bounds
  useEffect(() => {
    if (childrenBoundsApi.hasCluster) {
      return undefined
    }

    const childrenBoundsId = `marker-${markerId}-${latitude}-${longitude}`

    childrenBoundsApi.add({
      id: childrenBoundsId,
      latitudes: [latitude],
      longitudes: [longitude],
    })

    return () => {
      childrenBoundsApi.remove({ id: childrenBoundsId })
    }
  }, [childrenBoundsApi, latitude, longitude, markerId])

  // Update the marker position reference
  useEffect(() => {
    positionRef.current = { latitude, longitude }
  }, [latitude, longitude])

  // Call onChange when marker changes
  useEffect(() => {
    if (marker && stableOnChange) {
      stableOnChange({ openInfo: info ? openInfo : undefined })
    }
  }, [info, latitude, longitude, marker, openInfo, stableOnChange])

  return {
    eventListeners,
    initialPropsRef,
    interactable,
    isInfoOpenRef,
    marker,
    positionRef,
    setMarker,
    sharedPopper,
  }
}

useMarker.propTypes = {
  ariaLabel: PropTypes.string.isRequired,
  chars: PropTypes.oneOfType([PropTypes.number, PropTypes.string]),
  color: PropTypes.oneOf(['blue', 'gray', 'green', 'purple', 'red', 'yellow']),
  draggable: PropTypes.bool,
  focused: PropTypes.bool,
  Icon: PropTypes.func,
  imageSrc: PropTypes.string,
  info: PropTypes.oneOfType([PropTypes.string, PropTypes.func, PropTypes.element, PropTypes.node]),
  label: PropTypes.oneOfType([PropTypes.string, PropTypes.func, PropTypes.element, PropTypes.node]),
  latitude: PropTypes.number.isRequired,
  longitude: PropTypes.number.isRequired,
  metadata: PropTypes.any,
  onBlur: PropTypes.func,
  onClick: PropTypes.func,
  onDragEnd: PropTypes.func,
  onFocus: PropTypes.func,
  onInfoClosed: PropTypes.func,
  onMouseEnter: PropTypes.func,
  onMouseLeave: PropTypes.func,
  onChange: PropTypes.func,
  testId: PropTypes.string,
  title: PropTypes.string,
}
